#include <stdio.h>
#include <stdlib.h>
#define MAX_N 100
#define MAX_M 10000
typedef struct Edge {
    int u, v, w;
} Edge;
int compare(const void *a, const void *b) {
    Edge *e1 = (Edge *)a;
    Edge *e2 = (Edge *)b;
    return e1->w - e2->w;
}
int find(int *parent, int i) {
    if (parent[i] == i) return i;
    return find(parent, parent[i]);
}
void unionSet(int *parent, int *rank, int u, int v) {
    int x = find(parent, u);
    int y = find(parent, v);
    if (x != y) {
        if (rank[x] < rank[y]) {
            parent[x] = y;
        } else if (rank[x] > rank[y]) {
            parent[y] = x;
        } else {
            parent[y] = x;
            rank[x]++;
        }
    }
}
int kruskal(Edge *edges, int n, int m) {
    int *parent = (int *)malloc(n * sizeof(int));
    int *rank = (int *)malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) {
        parent[i] = i;
        rank[i] = 0;
    }
    qsort(edges, m, sizeof(Edge), compare);
    int sum = 0;
    for (int i = 0; i < m; i++) {
        int u = edges[i].u;
        int v = edges[i].v;
        int w = edges[i].w;
        if (find(parent, u) != find(parent, v)) {
            unionSet(parent, rank, u, v);
            sum += w;
        }
    }
    free(parent);
    free(rank);
    return sum;
}
int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n;
        scanf("%d", &n);
        Edge *edges = (Edge *)malloc(n * n * sizeof(Edge));
        int m = 0;
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                int w;
                scanf("%d", &w);
                if (w > 0 && i < j) {
                    edges[m].u = i;
                    edges[m].v = j;
                    edges[m].w = w;
                    m++;
                }
            }
        }
        if (m == 0) {
            printf("-1\n");
        } else {
            printf("%d\n", kruskal(edges, n, m));
        }
        free(edges);
    }
    return 0;
}

