from functools import cmp_to_key
class Edge:
    def __init__(self, u, v, w):
        self.u = u
        self.v = v
        self.w = w

def find(parent, i):
    if parent[i] == i:
        return i
    return find(parent, parent[i])

def unionSet(parent, rank, u, v):
    x = find(parent, u)
    y = find(parent, v)
    if x != y:
        if rank[x] < rank[y]:
            parent[x] = y
        elif rank[x] > rank[y]:
            parent[y] = x
        else:
            parent[y] = x
            rank[x] += 1

def kruskal(edges, n, m):
    parent = [i for i in range(n)]
    rank = [0 for _ in range(n)]
    edges.sort(key=cmp_to_key(lambda x, y: x.w - y.w))
    total = 0
    for i in range(m):
        u = edges[i].u
        v = edges[i].v
        w = edges[i].w
        if find(parent, u) != find(parent, v):
            unionSet(parent, rank, u, v)
            total += w
    return total

